module RefModule (  
    input wire clk,  
    input wire rst,  
    input wire [7:0] temperature,  
    input wire [7:0] threshold,  
    output reg shutdown  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst)  
            shutdown <= 0;  
        else if (temperature > threshold)  
            shutdown <= 1;  
    end  
endmodule
